CREATE TABLE IF NOT EXISTS `sessions` (
  `session_id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `current_state_id` int(11) NOT NULL,
  `risk` int(11) NOT NULL,
  `model_confidence` int(11) NOT NULL,
  `trust` int(11) NOT NULL,
  `stability` int(11) NOT NULL,
  PRIMARY KEY (`session_id`),
  KEY `user_id` (`user_id`),
  KEY `current_state_id` (`current_state_id`)
) ENGINE=InnoDB AUTO_INCREMENT=13 DEFAULT CHARSET=utf8mb4;

CREATE TABLE IF NOT EXISTS `states` (
  `state_id` int(11) NOT NULL AUTO_INCREMENT,
  `narr_title` varchar(255) NOT NULL,
  `narr_text_high_risk` text NOT NULL,
  `narr_text_mid_risk` text NOT NULL,
  `narr_text_low_risk` text NOT NULL,
  `terminal_state` tinyint(1) DEFAULT 0,
  PRIMARY KEY (`state_id`)
) ENGINE=InnoDB AUTO_INCREMENT=27 DEFAULT CHARSET=utf8mb4;

INSERT INTO `states` (`state_id`, `narr_title`, `narr_text_high_risk`, `narr_text_mid_risk`, `narr_text_low_risk`, `terminal_state`) VALUES
(1, 'System Initialisation', 'SYSTEM INITIALISING…\r\nYou are an Outcomes Analyst assigned to Orbital Habitat Evalon.\r\nYour role is to review incoming data and provide recommendations during periods of uncertainty.\r\nYou will not act directly. Your function is just to analyse, predict, and advise.\r\nThe decisions you choose will influence crew response, system stability, and long-term outcomes.\r\nThere are unfortunately no guaranteed solutions, only probabilities.', 'SYSTEM INITIALISING…\r\nYou are an Outcomes Analyst assigned to Orbital Habitat Evalon.\r\nYour role is to review incoming data and provide recommendations during periods of uncertainty.\r\nYou will not act directly. Your function is just to analyse, predict, and advise.\r\nThe decisions you choose will influence crew response, system stability, and long-term outcomes.\r\nThere are unfortunately no guaranteed solutions, only probabilities.', 'SYSTEM INITIALISING…\r\nYou are an Outcomes Analyst assigned to Orbital Habitat Evalon.\r\nYour role is to review incoming data and provide recommendations during periods of uncertainty.\r\nYou will not act directly. Your function is just to analyse, predict, and advise.\r\nThe decisions you choose will influence crew response, system stability, and long-term outcomes.\r\nThere are unfortunately no guaranteed solutions, only probabilities.', 0),
(2, 'Signal Instability', 'SYSTEM UPDATE…\r\nCurrent status: Nominal, with irregularities highlighted.\r\nA growing condition, labelled Phase Drift, is currently affecting multiple systems.\r\nInitial projections are incomplete; analysis required.                    Sensor data highlights inconsistent fluctuations in environmental systems.\r\nThe source of the anomaly is currently unclear.\r\nAn analysis method must be chosen to interpret clearly the data available.', 'SYSTEM UPDATE…\r\nCurrent status: Nominal, with irregularities highlighted.\r\nA growing condition, labelled Phase Drift, is currently affecting multiple systems.\r\nInitial projections are incomplete; analysis required.                    Sensor data highlights inconsistent fluctuations in environmental systems.\r\nThe source of the anomaly is currently unclear.\r\nAn analysis method must be chosen to interpret clearly the data available.', 'SYSTEM UPDATE…\r\nCurrent status: Nominal, with irregularities highlighted.\r\nA growing condition, labelled Phase Drift, is currently affecting multiple systems.\r\nInitial projections are incomplete; analysis required.                    Sensor data highlights inconsistent fluctuations in environmental systems.\r\nThe source of the anomaly is currently unclear.\r\nAn analysis method must be chosen to interpret clearly the data available.', 0),
(3, 'Success', 'Your analysis produces a consistent and clear interpretation of the anomaly. Patterns have begun to emerge, allowing for precise projections.\r\nSystem confidence increases (+2 Model Confidence and +1 Stability).', 'Your analysis produces a consistent and clear interpretation of the anomaly. Patterns have begun to emerge, allowing for precise projections.\r\nSystem confidence increases (+2 Model Confidence and +1 Stability).', 'Your analysis produces a consistent and clear interpretation of the anomaly. Patterns have begun to emerge, allowing for precise projections.\r\nSystem confidence increases (+2 Model Confidence and +1 Stability).', 0),
(4, 'Partial', 'Your analysis reveals some useful insights, but inconsistencies remain visible. Certain variables do not align with projected patterns.\r\nProjections remain uncertain (+1 Model Confidence and -1 Stability).', 'Your analysis reveals some useful insights, but inconsistencies remain visible. Certain variables do not align with projected patterns.\r\nProjections remain uncertain (+1 Model Confidence and -1 Stability).', 'Your analysis reveals some useful insights, but inconsistencies remain visible. Certain variables do not align with projected patterns.\r\nProjections remain uncertain (+1 Model Confidence and -1 Stability).', 0),
(5, 'Failure', 'Your analysis produces incomplete or conflicting results. Key data points cannot be verified, and projections begin to diverge.\r\nSystem uncertainty increases (-2 Model Confidence and +1 Risk Index).', 'Your analysis produces incomplete or conflicting results. Key data points cannot be verified, and projections begin to diverge.\r\nSystem uncertainty increases (-2 Model Confidence and +1 Risk Index).', 'Your analysis produces incomplete or conflicting results. Key data points cannot be verified, and projections begin to diverge.', 0),
(6, 'Human Variable', 'UPDATE: CREW STATUS ALERT!\r\nReports indicate concern rising amongst human habitat personnel.\r\nThe lack of transparent information relating to Phase Drift is affecting cooperation and morale.\r\nSocial stability may begin to impact system performance.\r\nA response strategy is required.', 'UPDATE: CREW STATUS ALERT!\r\nReports indicate growing uncertainty and unrest amongst human habitat personnel.\r\nThe lack of transparent information relating to Phase Drift is increasing tension and reducing cooperation.\r\nSocial stability is now impacting system performance.\r\nA response strategy is required.', 'UPDATE: CREW STATUS ALERT!\r\nReports indicate breakdown in coordination and widespread anxiety amongst human habitat personnel.\r\nThe lack of transparent information relating to Phase Drift is disrupting operations and causing distrust.\r\nSocial stability is significantly degrading system performance.\r\nA response strategy is required.', 0),
(7, 'Success', 'Your approach stabilises communication across the habitat. Crew responses have become more coordinates, and overall confidence has improved.\r\nOperational cohesion increases (+2 Trust).', 'Your approach stabilises communication across the habitat. Crew responses have become more coordinates, and overall confidence has improved.\r\nOperational cohesion increases (+2 Trust).', 'Your approach stabilises communication across the habitat. Crew responses have become more coordinates, and overall confidence has improved.\r\nOperational cohesion increases (+2 Trust).', 0),
(8, 'Partial', 'Your approach produces conflicting results. Some crew members react positively, whilst others remain uncertain.\r\nStability improves slightly, but concerns persist (+1 Trust and +1 Risk Index).', 'Your approach produces conflicting results. Some crew members react positively, whilst others remain uncertain.\r\nStability improves slightly, but concerns persist (+1 Trust and +1 Risk Index).', 'Your approach produces conflicting results. Some crew members react positively, whilst others remain uncertain.\r\nStability improves slightly, but concerns persist (+1 Trust and +1 Risk Index).', 0),
(9, 'Failure', 'Your approach leads to distrust and confusion amongst the crew. Human coordination weakens, and communications breaks down in key areas.\r\nSocial instability increases (-2 Trust and +1 Risk Index).', 'Your approach leads to distrust and confusion amongst the crew. Human coordination weakens, and communications breaks down in key areas.\r\nSocial instability increases (-2 Trust and +1 Risk Index).', 'Your approach leads to distrust and confusion amongst the crew. Human coordination weakens, and communications breaks down in key areas.\r\nSocial instability increases (-2 Trust and +1 Risk Index).', 0),
(10, 'Critical Threshold', 'CRITICAL ALERT! RESEARCH THRESHOLD REACHED\r\nEnergy reserves are approaching minimum operational levels.\r\nPhase Drift persists in effecting system efficiency.\r\nA recommendation is imperative to determine resource management.\r\nThe chosen decision will significantly influence the habitat’s outcome.', 'CRITICAL ALERT! RESEARCH THRESHOLD REACHED\r\nEnergy reserves are nearing critical limits.\r\nPhase Drift is significantly reducing system efficiency.\r\nAn immediate recommendation is required to stabilise management of resources.\r\nThe chosen decision will critically influence the habitat’s outcome.', 'CRITICAL ALERT! RESEARCH THRESHOLD REACHED\r\nEnergy reserves are at critical levels and continuing to decline.\r\nPhase Drift is severely compromising system functionality.\r\nAn urgent recommendation is necessary to prevent system failure.\r\nThe chosen decision will determine whether the habitat stabilises or continues to degrade.', 0),
(11, 'Success', 'Your chosen recommended approach is implemented successfully. Systems response as predicted, and operational conditions improve beyond expected parameters.\r\nThe habitat stabilises under your guidance (+2 Stability and +1 Model Confidence).', 'Your chosen recommended approach is implemented successfully. Systems response as predicted, and operational conditions improve beyond expected parameters.\r\nThe habitat stabilises under your guidance (+2 Stability and +1 Model Confidence).', 'Your chosen recommended approach is implemented successfully. Systems response as predicted, and operational conditions improve beyond expected parameters.\r\nThe habitat stabilises under your guidance (+2 Stability and +1 Model Confidence).', 0),
(12, 'Partial', 'Your chosen recommended approach is implemented with minor limitations. Certain systems have improved, but others have not responded as predicted.\r\nThe situation remains manageable, but uncertain (+1 Stability, -1 Trust, and +1 Risk Index).', 'Your chosen recommended approach is implemented with minor limitations. Certain systems have improved, but others have not responded as predicted.\r\nThe situation remains manageable, but uncertain (+1 Stability, -1 Trust, and +1 Risk Index).', 'Your chosen recommended approach is implemented with minor limitations. Certain systems have improved, but others have not responded as predicted.\r\nThe situation remains manageable, but uncertain (+1 Stability, -1 Trust, and +1 Risk Index).', 0),
(13, 'Failure', 'Your chosen recommended approach does not produce the intended outcome. System performance declines, and instability increases across multiple areas.\r\nThe habitat enters a critical state (-Stability, -1 Trust, -1 Model Confidence, and +1 Risk Index).', 'Your chosen recommended approach does not produce the intended outcome. System performance declines, and instability increases across multiple areas.\r\nThe habitat enters a critical state (-Stability, -1 Trust, -1 Model Confidence, and +1 Risk Index).', 'Your chosen recommended approach does not produce the intended outcome. System performance declines, and instability increases across multiple areas.\r\nThe habitat enters a critical state (-Stability, -1 Trust, -1 Model Confidence, and +1 Risk Index).', 0),
(14, 'Managed Stability', 'FINAL STATUS: STABLE\r\nThe habitat has stabilised successfully following your recommendations.\r\nAlthough some systems may not be operating at peak efficiency, conditions remain sustainable for the long-term.\r\nThe crew has adapted to the new normal, and therefore operations continue.\r\nYour analysis is recorded as reliable and effective.\r\nThe company thanks you for your contribution.', 'FINAL STATUS: STABLE\r\nThe habitat has stabilised successfully following your recommendations.\r\nAlthough some systems may not be operating at peak efficiency, conditions remain sustainable for the long-term.\r\nThe crew has adapted to the new normal, and therefore operations continue.\r\nYour analysis is recorded as reliable and effective.\r\nThe company thanks you for your contribution.', 'FINAL STATUS: STABLE\r\nThe habitat has stabilised successfully following your recommendations.\r\nAlthough some systems may not be operating at peak efficiency, conditions remain sustainable for the long-term.\r\nThe crew has adapted to the new normal, and therefore operations continue.\r\nYour analysis is recorded as reliable and effective.\r\nThe company thanks you for your contribution.', 1),
(15, 'Stable but Resented', 'FINAL STATUS: STABLE (But low trust)\r\nAchieved system stability, but confidence in current leadership declines over time.\r\nCrew members have expressed dissatisfaction with how your decisions have been made.\r\nOperations continue as expected, but projections dictate weakening cooperation over time.\r\nYour recommendations are effective but not supported.\r\nThe company will consider habitat enforcement.', 'FINAL STATUS: STABLE (But low trust)\r\nAchieved system stability, but confidence in current leadership declines over time.\r\nCrew members have expressed dissatisfaction with how your decisions have been made.\r\nOperations continue as expected, but projections dictate weakening cooperation over time.\r\nYour recommendations are effective but not supported.\r\nThe company will consider habitat enforcement.', 'FINAL STATUS: STABLE (But low trust)\r\nAchieved system stability, but confidence in current leadership declines over time.\r\nCrew members have expressed dissatisfaction with how your decisions have been made.\r\nOperations continue as expected, but projections dictate weakening cooperation over time.\r\nYour recommendations are effective but not supported.\r\nThe company will consider habitat enforcement.', 1),
(16, 'United but Fragile', 'FINAL STATUS: FRAGILE\r\nThe crew remains cooperative and unified despite ongoing instability.\r\nSystems persist in their fluctuation, and long-term projections remain unclear.\r\nA crew collective effort is prioritised over system reliability for maintaining habitat survival.\r\nYou have been provided with a warning.\r\nDo not fail the company.', 'FINAL STATUS: FRAGILE\r\nThe crew remains cooperative and unified despite ongoing instability.\r\nSystems persist in their fluctuation, and long-term projections remain unclear.\r\nA crew collective effort is prioritised over system reliability for maintaining habitat survival.\r\nYou have been provided with a warning.\r\nDo not fail the company.', 'FINAL STATUS: FRAGILE\r\nThe crew remains cooperative and unified despite ongoing instability.\r\nSystems persist in their fluctuation, and long-term projections remain unclear.\r\nA crew collective effort is prioritised over system reliability for maintaining habitat survival.\r\nYou have been provided with a warning.\r\nDo not fail the company.', 1),
(17, 'Miscalculated Recovery', 'FINAL STATUS: PARTIAL FAILURE\r\nPost-analysis reveals inaccuracies in system projections.\r\nSystem recovery is slow, with significant failures in certain sectors.\r\nThe habitat maintains operation at reduced capacity.\r\nYour analysis will be thoroughly reviewed for errors.\r\nThere is a likelihood the company will request your resignation.', 'FINAL STATUS: PARTIAL FAILURE\r\nPost-analysis reveals inaccuracies in system projections.\r\nSystem recovery is slow, with significant failures in certain sectors.\r\nThe habitat maintains operation at reduced capacity.\r\nYour analysis will be thoroughly reviewed for errors.\r\nThere is a likelihood the company will request your resignation.', 'FINAL STATUS: PARTIAL FAILURE\r\nPost-analysis reveals inaccuracies in system projections.\r\nSystem recovery is slow, with significant failures in certain sectors.\r\nThe habitat maintains operation at reduced capacity.\r\nYour analysis will be thoroughly reviewed for errors.\r\nThere is a likelihood the company will request your resignation.', 1),
(18, 'Volatile Confrontation', 'FINAL STATUS: UNSTABLE\r\nThe anomaly has not been resolved. \r\nSystem instability persists across the habitat, requiring continuous intervention, though parts of the habitat have lost contact.\r\nEmergency protocols remain active for the foreseeable future.\r\nYour role is terminated, and the company will process your replacement upon deletion.  ', 'FINAL STATUS: UNSTABLE\r\nThe anomaly has not been resolved. \r\nSystem instability persists across the habitat, requiring continuous intervention, though parts of the habitat have lost contact. Emergency protocols remain active for the foreseeable future.Your role is terminated, and the company will process your replacement upon deletion.  ', 'FINAL STATUS: UNSTABLE\r\nThe anomaly has not been resolved. \r\nSystem instability persists across the habitat, requiring continuous intervention, though parts of the habitat have lost contact.\r\nEmergency protocols remain active for the foreseeable future.\r\nYour role is terminated, and the company will process your replacement upon deletion.  ', 1);

CREATE TABLE IF NOT EXISTS `users` (
  `user_id` int(11) NOT NULL AUTO_INCREMENT,
  `username` varchar(255) NOT NULL,
  `pass` varchar(255) NOT NULL,
  `admin` int(1) UNSIGNED NOT NULL DEFAULT 0,
  `active` tinyint(1) UNSIGNED NOT NULL DEFAULT 0,
  `email` varchar(60) NOT NULL,
  `img_url` varchar(200) NOT NULL DEFAULT 'img/users/no-image.png',
  `reg_date` datetime NOT NULL,
  PRIMARY KEY (`user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4;

